input.newString:
export function formatTitle(value, mode = 'plain') {
  if (mode === 'upper') return value.toUpperCase()
  if (mode === 'lower') return value.toLowerCase()
  if (mode === 'title') return formatTitleAsTitle(value)
  return value
}

function formatTitleAsTitle(value) {
  return value
    .split(' ')
    .map((word, i) =>
      i === 0 ? word.charAt(0).toUpperCase() + word.slice(1).toLowerCase() : word
    )
    .join(' ')
}

